/// <summary>
///   Finds the start date of the next available open and on-hold fiscal calendar period.
/// </summary>
/// <param name="_calendarRecId">
///   The record ID of the <c>FiscalCalendar</c> record.
/// </param>
/// <param name="_date">
///    The date to start from.
/// </param>
/// <returns>
///    The start date of the next available open fiscal calendar period.
/// </returns>
public static FiscalPeriodStart findFirstOpenStartDateInAnyYear(FiscalCalendarRecId _calendarRecId, FiscalPeriodStart _date)
{
    FiscalCalendarPeriod       fiscalCalendarPeriod;
    LedgerFiscalCalendarPeriod ledgerFiscalCalendarPeriod;
    FiscalPeriodStart          startdate;

    select firstonly StartDate from fiscalCalendarPeriod
            order by StartDate
        where fiscalCalendarPeriod.StartDate >= LedgerFiscalCalendar::findPeriodStartDateByDateWithIndex(_calendarRecId, _date)
            && fiscalCalendarPeriod.Type == FiscalPeriodType::Operating
    exists join ledgerFiscalCalendarPeriod
        where ledgerFiscalCalendarPeriod.FiscalCalendarPeriod == fiscalCalendarPeriod.RecId
            && ledgerFiscalCalendarPeriod.Ledger == Ledger::current()
            && (ledgerFiscalCalendarPeriod.Status == FiscalPeriodStatus::Open || ledgerFiscalCalendarPeriod.Status == FiscalPeriodStatus::OnHold);

    if (_date >= fiscalCalendarPeriod.StartDate)
    {
        startdate = _date;
    }
    else
    {
        startdate = fiscalCalendarPeriod.StartDate;
    }

    return startdate;
}
